 42→function findJsonPath(doc: string, path: string): { from: number; to: number } | null {
 43→  const segments = path.split('/').filter(Boolean);
 44→  let pos = 0;
 45→
 46→  for (const seg of segments) {
 47→    const isIndex = /^\d+$/.test(seg);
 48→
 49→    if (isIndex) {
 50→      const idx = parseInt(seg, 10);
 51→      let bracketDepth = 0;
 52→      let currentIdx = -1;
 53→      const arrStart = doc.indexOf('[', pos);
 54→      if (arrStart === -1) return null;
 55→      pos = arrStart + 1;
 56→
 57→      while (pos < doc.length && currentIdx < idx) {
 58→        const ch = doc[pos];
 59→        if (ch === '[' || ch === '{') bracketDepth++;
 60→        else if (ch === ']' || ch === '}') bracketDepth--;
 61→        else if (ch === ',' && bracketDepth === 0) currentIdx++;
 62→        else if (bracketDepth === 0 && /[^\s,]/.test(ch) && currentIdx < idx) {
 63→          if (currentIdx === -1) currentIdx = 0;
 64→          if (currentIdx === idx) break;
 65→        }
 66→        if (bracketDepth < 0) break;
 67→        pos++;
 68→      }
 69→
 70→      if (currentIdx < idx - 1) {
 71→        const lastBrace = doc.lastIndexOf('{', pos);
 72→        if (lastBrace >= arrStart) pos = lastBrace;
 73→      }
 74→    } else {
 75→      const escaped = seg.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 76→      const keyPattern = new RegExp(`(?:"${escaped}"|${escaped})\\s*:`);
 77→      const match = keyPattern.exec(doc.slice(pos));
 78→      if (!match) return null;
 79→      pos += match.index;
 80→    }
 81→  }
 82→
 83→  let lineEnd = doc.indexOf('\n', pos);
 84→  if (lineEnd === -1) lineEnd = doc.length;
 85→
 86→  return { from: pos, to: Math.min(pos + 40, lineEnd) };
 87→}
