195→export function validateSduiJson(doc: string): Diagnostic[] {
196→  let parsed: any;
197→
198→  try {
199→    parsed = JSON.parse(doc);
200→  } catch {
201→    try {
202→      parsed = JSON5.parse(doc);
203→    } catch {
204→      return [];
205→    }
206→  }
207→
208→  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
209→    return [{
210→      from: 0,
211→      to: Math.min(doc.length, 1),
212→      severity: 'error',
213→      message: 'SDUI screen must be a JSON object',
214→      source: 'sdui-schema',
215→    }];
216→  }
217→
218→  const diagnostics: Diagnostic[] = [];
219→
220→  validate(parsed);
221→  if (validate.errors) {
222→    for (const error of validate.errors) {
223→      if (error.keyword === 'if') continue;
224→
225→      const jsonPath = error.instancePath || '';
226→      const loc = findJsonPath(doc, jsonPath);
227→      const msg = humanizeMessage(error);
228→
229→      diagnostics.push({
230→        from: loc?.from ?? 0,
231→        to: loc?.to ?? 0,
232→        severity: error.keyword === 'required' || error.keyword === 'type' ? 'error' : 'warning',
233→        message: msg,
234→        source: 'sdui-schema',
235→      });
236→    }
237→  }
238→
239→  diagnostics.push(...validateComponentProps(parsed, doc));
240→
241→  const seen = new Set<string>();
242→  return diagnostics.filter(d => {
243→    const key = `${d.from}:${d.message}`;
244→    if (seen.has(key)) return false;
245→    seen.add(key);
246→    return true;
247→  });
248→}
249→
250→export function sduiSchemaLinter(view: EditorView): Diagnostic[] {
251→  return validateSduiJson(view.state.doc.toString());
252→}
