212→export const CodeMirrorEditor = forwardRef<
213→  CodeMirrorEditorHandle,
214→  CodeMirrorEditorProps
215→>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false }, ref) {
216→  const containerRef = useRef<HTMLDivElement>(null);
217→  const viewRef = useRef<EditorView | null>(null);
218→  const onChangeRef = useRef(onChange);
219→  const onValidationChangeRef = useRef(onValidationChange);
220→  const isExternalUpdate = useRef(false);
221→
222→  const themeCompartment = useMemo(() => new Compartment(), []);
223→  const highlightCompartment = useMemo(() => new Compartment(), []);
224→
225→  onChangeRef.current = onChange;
226→  onValidationChangeRef.current = onValidationChange;
227→
228→  useImperativeHandle(ref, () => ({
229→    getValue: () => viewRef.current?.state.doc.toString() ?? '',
230→    setValue: (val: string) => {
231→      const view = viewRef.current;
232→      if (!view) return;
233→      isExternalUpdate.current = true;
234→      view.dispatch({
235→        changes: { from: 0, to: view.state.doc.length, insert: val },
236→      });
237→      isExternalUpdate.current = false;
238→    },
239→    getView: () => viewRef.current,
240→  }));
241→
242→  useEffect(() => {
243→    if (!containerRef.current) return;
244→
245→    const json5ParseLinter = linter(
246→      (view): Diagnostic[] => {
247→        const doc = view.state.doc.toString();
248→        if (!doc.trim()) return [];
249→        try {
250→          JSON5.parse(doc);
251→          onValidationChangeRef.current?.(false, null);
252→          return [];
253→        } catch (e) {
254→          const msg = (e as SyntaxError).message || 'Invalid JSON';
255→          const lineMatch = msg.match(/at (\d+):(\d+)/);
256→          let from = 0;
257→          let to = Math.min(doc.length, 1);
258→          if (lineMatch) {
259→            const line = parseInt(lineMatch[1], 10);
260→            const col = parseInt(lineMatch[2], 10);
261→            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
262→            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
263→            to = Math.min(from + 1, lineInfo.to);
264→          }
265→          onValidationChangeRef.current?.(true, msg);
266→          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
267→        }
268→      },
269→      { delay: 300 },
270→    );
271→
272→    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });
273→
274→    const updateListener = EditorView.updateListener.of(update => {
275→      if (update.docChanged && !isExternalUpdate.current) {
276→        const doc = update.state.doc.toString();
277→        onChangeRef.current(doc);
278→      }
279→    });
280→
281→    const initialTheme = isDarkMode ? darkTheme : lightTheme;
282→    const initialHighlight = isDarkMode
283→      ? syntaxHighlighting(darkHighlightStyle)
284→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
285→
286→    const state = EditorState.create({
287→      doc: value,
288→      extensions: [
289→        lineNumbers(),
290→        highlightActiveLineGutter(),
291→        highlightActiveLine(),
292→        drawSelection(),
293→        rectangularSelection(),
294→        bracketMatching(),
295→        foldGutter(),
296→        highlightSelectionMatches(),
297→        history(),
298→        javascript(),
299→        highlightCompartment.of(initialHighlight),
300→        lintGutter(),
301→        json5ParseLinter,
302→        schemaLinter,
303→        themeCompartment.of(initialTheme),
304→        updateListener,
305→        keymap.of([
306→          ...defaultKeymap,
307→          ...historyKeymap,
308→          ...foldKeymap,
309→          ...searchKeymap,
310→          indentWithTab,
311→        ]),
312→        EditorView.lineWrapping,
313→        EditorState.tabSize.of(2),
314→      ],
315→    });
316→
317→    const view = new EditorView({
318→      state,
319→      parent: containerRef.current,
320→    });
321→
322→    viewRef.current = view;
323→
324→    return () => {
325→      view.destroy();
326→      viewRef.current = null;
327→    };
328→  // eslint-disable-next-line react-hooks/exhaustive-deps
329→  }, []);
330→
331→  useEffect(() => {
332→    const view = viewRef.current;
333→    if (!view) return;
334→
335→    const newTheme = isDarkMode ? darkTheme : lightTheme;
336→    const newHighlight = isDarkMode
337→      ? syntaxHighlighting(darkHighlightStyle)
338→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
339→
340→    view.dispatch({
341→      effects: [
342→        themeCompartment.reconfigure(newTheme),
343→        highlightCompartment.reconfigure(newHighlight),
344→      ],
345→    });
346→  }, [isDarkMode, themeCompartment, highlightCompartment]);
347→
348→  useEffect(() => {
349→    const view = viewRef.current;
350→    if (!view) return;
351→    const currentDoc = view.state.doc.toString();
352→    if (currentDoc !== value && value) {
353→      isExternalUpdate.current = true;
354→      view.dispatch({
355→        changes: { from: 0, to: view.state.doc.length, insert: value },
356→      });
357→      isExternalUpdate.current = false;
358→    }
359→  }, [value]);
360→
361→  return (
362→    <div
363→      ref={containerRef}
364→      style={{ height: '100%', overflow: 'hidden' }}
365→    />
366→  );
367→});
